    expect(() => recordDeposit('alice', 0)).toThrow(
      'amount must be a positive number',
    )
  })

  it('rejects a deposit with more than two decimal places', () => {
    expect(() => recordDeposit('alice', 1.234)).toThrow(
      'amount must have at most two decimal places',
    )
  })

  it('records a withdrawal entry', () => {
    expect(recordWithdrawal('  Bob ', 40)).toEqual({
      account: 'bob',
      amount: -40,
      kind: 'withdrawal',
    })
  })
})

export type LedgerEntry = {
  account: string
  amount: number
  kind: 'deposit' | 'withdrawal'
}

const entries: LedgerEntry[] = []

export function recordDeposit(account: string, amount: number): LedgerEntry {
  const owner = account.trim().toLowerCase()
  if (owner === '') {
    throw new Error('account is required')
  }
  if (!Number.isFinite(amount) || amount <= 0) {
    throw new Error('amount must be a positive number')
  }
  if (Math.round(amount * 100) !== amount * 100) {
    throw new Error('amount must have at most two decimal places')
  }
  const entry: LedgerEntry = { account: owner, amount, kind: 'deposit' }
  entries.push(entry)
  return entry
}

export function recordWithdrawal(account: string, amount: number): LedgerEntry {
  const owner = account.trim().toLowerCase()
  if (owner === '') {
    throw new Error('account is required')
  }
  if (!Number.isFinite(amount) || amount <= 0) {
    throw new Error('amount must be a positive number')
  }
  if (Math.round(amount * 100) !== amount * 100) {
    throw new Error('amount must have at most two decimal places')
  }
  const entry: LedgerEntry = { account: owner, amount: -amount, kind: 'withdrawal' }
  entries.push(entry)
  return entry
}
